#include <iostream>
#include <string>
#include <sstream>
#include <streambuf>

std::string run_program_logic(const std::string& input_str) {
    std::stringstream ss_input(input_str);
    std::stringstream ss_output;

    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    int score;
    std::cin >> score;

    if (score >= 60) {
        std::cout << "Pass" << std::endl;
    } else {
        std::cout << "Fail" << std::endl;
    }

    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    std::string output = ss_output.str();
    if (!output.empty() && output.back() == '\n') {
        output.pop_back();
    }
    if (!output.empty() && output.back() == '\r') {
        output.pop_back();
    }
    return output;
}
